template <typename Program, typename Shader>
template <typename Device, typename Layout, typename Resolver>
Shaders<Program, Shader>::Shaders(Device &device, Layout &layout, const Resolver &resolver)
{
	(void)resolver;
	layout.unserialize(reflection_bank + 0, 348);
	this->composite = device.request_program(spirv_bank + 0, 99920, &layout);
	layout.unserialize(reflection_bank + 348, 348);
	this->blit = device.request_shader(spirv_bank + 24980, 1148, &layout);
	layout.unserialize(reflection_bank + 696, 348);
	this->bloom = device.request_shader(spirv_bank + 25267, 12280, &layout);
	layout.unserialize(reflection_bank + 1044, 348);
	this->scan = device.request_shader(spirv_bank + 28337, 5988, &layout);
	layout.unserialize(reflection_bank + 1392, 348);
	this->sinc = device.request_shader(spirv_bank + 29834, 7300, &layout);
	if (resolver("iir", "SUBGROUP") == 0)
	{
		layout.unserialize(reflection_bank + 1740, 348);
		this->iir = device.request_program(spirv_bank + 31659, 4828, &layout);
	}
	if (resolver("iir", "SUBGROUP") == 1)
	{
		layout.unserialize(reflection_bank + 2088, 348);
		this->iir = device.request_program(spirv_bank + 32866, 6376, &layout);
	}
}
